use actix_web::{web, App, HttpServer, HttpResponse, Responder, Error};
use std::path::{Path, PathBuf};
use std::fs;

async fn serve_file(web::Path(filename): web::Path<String>) -> Result<impl Responder, Error> {
    let uploads_dir = Path::new("uploads");
    let file_path = uploads_dir.join(filename);

    if !file_path.starts_with(uploads_dir) {
        return Ok(HttpResponse::Forbidden().finish());
    }

    if file_path.exists() && file_path.is_file() {
        let file_content = fs::read(file_path).map_err(|_| HttpResponse::InternalServerError())?;
        Ok(HttpResponse::Ok().body(file_content))
    } else {
        Ok(HttpResponse::NotFound().finish())
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/files/{filename}", web::get().to(serve_file))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}